create table if not exists public.members (key text primary key, name text not null, role text not null, badge text not null, socials jsonb not null default '[]'::jsonb, sort_order integer not null default 0, created_at timestamptz not null default now());
alter table public.members add column if not exists socials jsonb not null default '[]'::jsonb;
create table if not exists public.posts (id text primary key, title text not null, description text not null default '', image_url text not null, image_path text not null default '', mime_type text not null default '', created_at timestamptz not null default now());
create table if not exists public.portraits (member_key text primary key references public.members(key) on delete cascade, image_url text not null, image_path text not null default '', mime_type text not null default '', updated_at timestamptz not null default now());
alter table public.members enable row level security;
alter table public.posts enable row level security;
alter table public.portraits enable row level security;
drop policy if exists members_public_read on public.members;
drop policy if exists posts_public_read on public.posts;
drop policy if exists portraits_public_read on public.portraits;
drop policy if exists members_admin_write on public.members;
drop policy if exists posts_admin_write on public.posts;
drop policy if exists portraits_admin_write on public.portraits;
create policy members_public_read on public.members for select using (true);
create policy posts_public_read on public.posts for select using (true);
create policy portraits_public_read on public.portraits for select using (true);
create policy members_admin_write on public.members for all to authenticated using ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin') with check ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
create policy posts_admin_write on public.posts for all to authenticated using ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin') with check ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
create policy portraits_admin_write on public.portraits for all to authenticated using ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin') with check ((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
insert into storage.buckets (id, name, public) values ('hudas-media', 'hudas-media', true) on conflict (id) do update set public = true;
alter table storage.objects enable row level security;
drop policy if exists hudas_media_public_read on storage.objects;
drop policy if exists hudas_media_admin_insert on storage.objects;
drop policy if exists hudas_media_admin_update on storage.objects;
drop policy if exists hudas_media_admin_delete on storage.objects;
create policy hudas_media_public_read on storage.objects for select using (bucket_id = 'hudas-media');
create policy hudas_media_admin_insert on storage.objects for insert to authenticated with check (bucket_id = 'hudas-media' and (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
create policy hudas_media_admin_update on storage.objects for update to authenticated using (bucket_id = 'hudas-media' and (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin') with check (bucket_id = 'hudas-media' and (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
create policy hudas_media_admin_delete on storage.objects for delete to authenticated using (bucket_id = 'hudas-media' and (auth.jwt() -> 'app_metadata' ->> 'role') = 'admin');
